    (!search.complianceCategory || String(row.complianceCategory ?? '').includes(String(search.complianceCategory))) &&
    (!search.inspectionPeriodFrom || String(row.inspectionPeriod ?? '') >= String(search.inspectionPeriodFrom)) &&
    (!search.inspectionPeriodTo   || String(row.inspectionPeriod ?? '') <= String(search.inspectionPeriodTo)) &&
    (!search.completionStatus || String(row.completionStatus ?? '') === 'true')
  ),
);

const totalPages = computed(() =>
  Math.max(1, Math.ceil(filteredRows.value.length / PAGE_SIZE)),
);

const pagedRows = computed(() =>
  filteredRows.value.slice((page.value - 1) * PAGE_SIZE, page.value * PAGE_SIZE),
);

